// Before: one large function with many branches
function process(data) {
  if (data.type === 'A') { /* ... */ }
  else if (data.type === 'B') { /* ... */ }
}

// After: strategy pattern
const handlers = { A: handleA, B: handleB };
function process(data) {
  return handlers[data.type](data);
}

// Before: deep nesting
function validate(user) {
  if (user) {
    if (user.email) {
      if (user.age > 18) {
        return true;
      }
    }
  }
  return false;
}

// After: guard clauses
function validate(user) {
  if (!user) return false;
  if (!user.email) return false;
  if (user.age <= 18) return false;
  return true;
}

// Before: duplicated validation in multiple files
// fileA.ts: if (email && email.includes('@')) { ... }
// fileB.ts: if (email && email.includes('@')) { ... }

// After: shared utility
// utils/validation.ts
export function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

// Before: vulnerable to SQL injection
const query = `SELECT * FROM users WHERE id = '${userId}'`;

// After: parameterized query
const query = 'SELECT * FROM users WHERE id = $1';
const result = await db.query(query, [userId]);

// Before: dangerous eval
const config = eval('(' + configString + ')');

// After: safe JSON parsing
const config = JSON.parse(configString);

// Before: hardcoded secret
const apiKey = 'sk-abc123secret';

// After: environment variable
const apiKey = process.env.API_KEY;
if (!apiKey) throw new Error('API_KEY environment variable is required');

// Before: no error handling
async function fetchData(url) {
  const response = await fetch(url);
  return response.json();
}

// After: proper error handling
async function fetchData(url) {
  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }
    return response.json();
  } catch (error) {
    logger.error('Failed to fetch data', { url, error });
    throw error;
  }
}

// Before: no validation
function createUser(data: any) {
  db.insert('users', data);
}

// After: schema validation with Zod
import { z } from 'zod';
const UserSchema = z.object({
  email: z.string().email(),
  name: z.string().min(1).max(100),
  age: z.number().int().positive(),
});

function createUser(data: unknown) {
  const validated = UserSchema.parse(data);
  db.insert('users', validated);
}

// Before: allowing HTTP
app.listen(3000);

// After: enforce HTTPS redirect
app.use((req, res, next) => {
  if (req.headers['x-forwarded-proto'] !== 'https') {
    return res.redirect(301, `https://${req.hostname}${req.url}`);
  }
  next();
});

// Using express-rate-limit
import rateLimit from 'express-rate-limit';

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});

app.use('/api/', limiter);

// Using helmet for Express
import helmet from 'helmet';

app.use(helmet({
  contentSecurityPolicy: true,
  crossOriginEmbedderPolicy: true,
  crossOriginOpenerPolicy: true,
  crossOriginResourcePolicy: true,
  hsts: { maxAge: 31536000, includeSubDomains: true },
  noSniff: true,
  referrerPolicy: { policy: 'strict-origin-when-cross-origin' },
}));

// Using a structured logger
import { Logger } from './logger';

const logger = new Logger({ service: 'user-api' });

async function createUser(data: UserInput) {
  logger.info('Creating user', { email: data.email });
  try {
    const user = await db.create(data);
    logger.info('User created', { userId: user.id });
    return user;
  } catch (error) {
    logger.error('User creation failed', { error, email: data.email });
    throw error;
  }
}

